css:
/* 定义按键和输入框的颜色 */
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader {
    background-image: none;
}

/* 全局去除所有元素的阴影效果 */
* {
    box-shadow: none !important; /* 去除所有元素的阴影 */
}

/* 定义颜色变量 */
* {
    --black30a: rgba(255, 255, 255, 0.3);
    --black50a: rgba(255, 255, 255, 0.5);
    --white30a: rgba(0, 0, 0, 0.4);
    --white50a: rgba(0, 0, 0, 0.5);
}

/* 顶部栏的图标颜色 */
#top-settings-holder {
    color: #B0B0B0; /* 改为灰色 #B0B0B0 */
}

.drawer-icon.closedIcon {
    opacity: 0.6 !important; /* 强制完全不透明 */
}

/* 输入框 */
#send_textarea {
    color: #000000; /* 黑色 */
    background-color: rgba(237, 237, 237, 0.5); /* 半透明的微信灰色 */
}

/* 滚动条 - 黑色 & 微信灰色 */
* {
    scrollbar-color: #000000 #EDEDED; /* 黑色和微信灰色 */
    scrollbar-width: thin;
}

/* 格式化文本 */
.formatted-text {
    color: #000000; /* 黑色 */
}

/* 代码块 */
/* 小代码块 */
code {
    background-color: rgba(237, 237, 237, 0.5); /* 微信灰色背景 */
    color: #000000; /* 黑色文字 */
    border: none; /* 不要边框 */
}

/* 禁用 .hljs 的背景颜色和文字颜色 */
.hljs {
    background-color: transparent !important;
    color: inherit !important;
}

/* 大代码块 */
pre {
    font-family: monospace;
    background-color: rgba(237, 237, 237, 0.3); /* 微信灰色背景 */
    color: #000000; /* 黑色文字 */
    padding: 10px;
    border-radius: 5px; /* 边角弧度改为5px */
    border: none; /* 不要边框 */
    background-clip: padding-box;
    position: relative;
}

/* 按钮和文本框 */
.menu_button, .text_pole, textarea {
    background-color: rgba(237, 237, 237, 0.5); /* 微信灰色 */
    color: #000000; /* 黑色 */
    border: 1px solid #000000; /* 边框为黑色 */
}

/* 编辑框黑色去除，并将背景设置为半透明微信灰色 */
.edit_textarea {
    background-color: rgba(237, 237, 237, 0.5) !important; /* 半透明的微信灰色 */
    color: #000000 !important; /* 黑色文字 */
    border: 1px solid #000000; /* 黑色边框 */
}

/* 消息气泡 */
body.bubblechat .mes {
    background-color: unset !important;
}

/* 用户消息块 */
body.bubblechat .mes_block {
    background-color: transparent; /* 设置气泡为透明 */
    padding: 6px 10px 2px 10px; /* 上: 6px, 左右: 10px, 下: 2px */
    border-radius: 5px; /* 将边角弧度改为5px */
    width: max-content;
    position: relative;
    max-width: 75%; /* 气泡最大宽度为聊天框的 75% */
    border: none; /* 不要边框 */
}

/* 用户消息块 - 对齐用户消息 */
body.bubblechat .mes[is_user="true"] .mes_block {
    background-color: transparent;
    order: -1;
    margin-left: auto;
    border-radius: 5px;
    position: relative;
    padding-right: 20px; /* 用户消息右侧留出20px */
    padding-left: 10px;  /* 左侧10px */
    padding-top: 6px;    /* 上方6px */
    padding-bottom: 2px; /* 下方2px */
    max-width: 75%;      /* 气泡最大宽度为聊天框的 75% */
    border: none;
}

/* 叠加一个绿色圆角矩形 - 用户消息 */
body.bubblechat .mes[is_user="true"] .mes_block::before {
    content: "";
    position: absolute;
    top: 0;
    right: 10px;
    bottom: 0;
    left: 0;
    background-color: #9EEA6A; /* 微信绿色 */
    border-radius: 5px;
    z-index: -1;
}

/* 用户气泡右上角的三角形 */
body.bubblechat .mes[is_user="true"] .mes_block::after {
    content: "";
    position: absolute;
    top: 20px;
    right: 5px;
    width: 0;
    height: 0;
    border-left: 5px solid #9EEA6A;
    border-top: 5px solid transparent;
    border-bottom: 5px solid transparent;
}

/* 叠加一个白色圆角矩形 - 系统消息 */
body.bubblechat .mes:not([is_user="true"]) .mes_block::before {
    content: "";
    position: absolute;
    top: 0;
    left: 10px;
    bottom: 0;
    right: 0;
    background-color: #FFFFFF;
    border-radius: 5px;
    z-index: -1;
}

/* 系统气泡左上角的三角形 */
body.bubblechat .mes:not([is_user="true"]) .mes_block::after {
    content: "";
    position: absolute;
    top: 20px;
    left: 5px;
    width: 0;
    height: 0;
    border-right: 5px solid #FFFFFF;
    border-top: 5px solid transparent;
    border-bottom: 5px solid transparent;
}

/* 系统消息块 - 调整文本对齐 */
body.bubblechat .mes:not([is_user="true"]) .mes_block {
    padding-left: 20px;  /* 系统消息左侧留出20px */
    padding-right: 10px; /* 右侧10px */
    padding-top: 6px;    /* 上方6px */
    padding-bottom: 2px; /* 下方2px */
    max-width: 75%;      /* 气泡最大宽度为聊天框的 75% */
    border: none;
}

/* 消息发送者名称 - 使用 max-height, max-width 和 opacity 实现平滑展开 */
.mes_block .ch_name {
    max-height: 0; /* 初始高度为0 */
    max-width: 0; /* 初始宽度为0 */
    overflow: hidden;
    opacity: 0;
    white-space: nowrap; /* 避免折行 */
    transition: max-height 0.5s cubic-bezier(0.25, 0.1, 0.25, 1), max-width 0.5s cubic-bezier(0.25, 0.1, 0.25, 1), opacity 0.5s cubic-bezier(0.25, 0.1, 0.25, 1);
}

/* 鼠标悬停时显示发送者名称，展开高度调整为58px，且随着气泡宽度动态调整 */
.mes_block:hover .ch_name {
    max-height: 58px; /* 调整为58px */
    max-width: 100%;  /* 随着气泡宽度动态调整 */
    opacity: 1; /* 渐变显示 */
}

/* QR设置 - 使用 max-height, max-width 和 opacity 实现平滑展开 */
#qr--bar {
    max-height: 0; /* 初始高度为0 */
    max-width: 0; /* 初始宽度为0 */
    overflow: hidden;
    opacity: 0;
    transition: max-height 0.5s cubic-bezier(0.25, 0.1, 0.25, 1), max-width 0.5s cubic-bezier(0.25, 0.1, 0.25, 1), opacity 0.5s cubic-bezier(0.25, 0.1, 0.25, 1);
}

/* 鼠标悬停时显示 QR 设置，展开高度调整为58px，且随着气泡宽度动态调整 */
#send_form:hover #qr--bar {
    max-height: 58px;  /* 调整为58px */
    max-width: 100%;   /* 随着气泡宽度动态调整 */
    opacity: 1;  /* 渐变显示 */
}

/* 隐藏代理警告 */
#ReverseProxyWarningMessage {
    display: none !important;
}

/* 删除按钮 */
#delete_button, .redWarningBG, .menu_button.popup-button-ok {
    background: linear-gradient(to bottom, rgba(255, 204, 229, 0.8), rgba(255, 160, 177, 0.8)) !important;
}

/* 范围输入框 */
.neo-range-input {
    background-color: rgba(237, 237, 237, 0.6); /* 微信灰色背景 */
    border: 1px solid #000000; /* 黑色边框 */
    color: #000000; /* 黑色文字 */
}

.range-block-counter input {
    background-color: rgba(237, 237, 237, 0.6); /* 微信灰色 */
    color: #000000; /* 黑色文字 */
    border: 1px solid #000000; /* 黑色边框 */
}

select {
    background-color: rgba(237, 237, 237, 0.6); /* 微信灰色 */
    color: #000000; /* 黑色文字 */
    border: 1px solid #000000; /* 黑色边框 */
}

table {
    color: #000000; /* 黑色文字 */
}
